package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.lang.reflect.Field;
import java.lang.reflect.Method;

class ExtendedBufferedReaderTest {

    private ExtendedBufferedReader extendedBufferedReader;
    private Reader mockReader;

    @BeforeEach
    void setUp() {
        mockReader = mock(Reader.class);
        extendedBufferedReader = new ExtendedBufferedReader(mockReader) {
            @Override
            public String readLine() throws IOException {
                return super.readLine();
            }
        };
    }

    @Test
    void testReadLine_NonNullNonEmptyLine() throws Exception {
        // Use spy to mock super.readLine()
        ExtendedBufferedReader spyReader = Mockito.spy(extendedBufferedReader);
        doReturn("hello").when(spyReader).readLine();

        // We need to call the real readLine() from BufferedReader superclass, so we invoke the focal method via reflection
        Method readLineMethod = ExtendedBufferedReader.class.getDeclaredMethod("readLine");
        readLineMethod.setAccessible(true);

        // Because spyReader.readLine() is mocked to return "hello", but inside focal method it calls super.readLine(), 
        // so we need to mock super.readLine() which is BufferedReader.readLine(), 
        // but BufferedReader is final, so we cannot mock directly.
        // Instead, create a subclass that overrides readLine() to return "hello".
        ExtendedBufferedReader reader = new ExtendedBufferedReader(mockReader) {
            @Override
            public String readLine() throws IOException {
                return "hello";
            }
        };
        // But this overrides focal method, so to test focal method we must test original ExtendedBufferedReader.
        // So we create a subclass that overrides BufferedReader.readLine() (super.readLine()) but not ExtendedBufferedReader.readLine().
        ExtendedBufferedReader reader2 = new ExtendedBufferedReader(mockReader) {
            @Override
            public String readLine() throws IOException {
                // call super.readLine() from BufferedReader, but we override BufferedReader.readLine() here:
                return super.readLine();
            }
            @Override
            public String superReadLine() throws IOException {
                return "hello";
            }
        };
        // This is complicated. Instead, use a custom Reader that returns "hello\n" on readLine.
        Reader readerWithHello = new Reader() {
            private boolean returned = false;
            @Override
            public int read(char[] cbuf, int off, int len) {
                if (returned) {
                    return -1;
                }
                String s = "hello\n";
                int length = Math.min(len, s.length());
                s.getChars(0, length, cbuf, off);
                returned = true;
                return length;
            }
            @Override
            public void close() {}
        };
        ExtendedBufferedReader reader3 = new ExtendedBufferedReader(readerWithHello);

        String line = reader3.readLine();

        assertEquals("hello", line);

        Field lastCharField = ExtendedBufferedReader.class.getDeclaredField("lastChar");
        lastCharField.setAccessible(true);
        int lastChar = lastCharField.getInt(reader3);
        assertEquals('o', lastChar);

        Field lineCounterField = ExtendedBufferedReader.class.getDeclaredField("lineCounter");
        lineCounterField.setAccessible(true);
        int lineCounter = lineCounterField.getInt(reader3);
        assertEquals(1, lineCounter);
    }

    @Test
    void testReadLine_NonNullEmptyLine() throws IOException, NoSuchFieldException, IllegalAccessException {
        Reader readerWithEmptyLine = new Reader() {
            private boolean returned = false;
            @Override
            public int read(char[] cbuf, int off, int len) {
                if (returned) {
                    return -1;
                }
                String s = "\n";
                int length = Math.min(len, s.length());
                s.getChars(0, length, cbuf, off);
                returned = true;
                return length;
            }
            @Override
            public void close() {}
        };
        ExtendedBufferedReader reader = new ExtendedBufferedReader(readerWithEmptyLine);

        String line = reader.readLine();

        assertEquals("", line);

        Field lastCharField = ExtendedBufferedReader.class.getDeclaredField("lastChar");
        lastCharField.setAccessible(true);
        int lastChar = lastCharField.getInt(reader);
        assertEquals(ExtendedBufferedReader.UNDEFINED, lastChar);

        Field lineCounterField = ExtendedBufferedReader.class.getDeclaredField("lineCounter");
        lineCounterField.setAccessible(true);
        int lineCounter = lineCounterField.getInt(reader);
        assertEquals(1, lineCounter);
    }

    @Test
    void testReadLine_NullLine() throws IOException, NoSuchFieldException, IllegalAccessException {
        Reader emptyReader = new Reader() {
            @Override
            public int read(char[] cbuf, int off, int len) {
                return -1;
            }
            @Override
            public void close() {}
        };
        ExtendedBufferedReader reader = new ExtendedBufferedReader(emptyReader);

        String line = reader.readLine();

        assertNull(line);

        Field lastCharField = ExtendedBufferedReader.class.getDeclaredField("lastChar");
        lastCharField.setAccessible(true);
        int lastChar = lastCharField.getInt(reader);
        assertEquals(ExtendedBufferedReader.END_OF_STREAM, lastChar);

        Field lineCounterField = ExtendedBufferedReader.class.getDeclaredField("lineCounter");
        lineCounterField.setAccessible(true);
        int lineCounter = lineCounterField.getInt(reader);
        assertEquals(0, lineCounter);
    }
}
